"""
自建配电网测试系统(用公开标准数据搭建)
  - build_case69(): IEEE/PG&E 69节点配电系统
    数据来源:Baran & Wu (1989) / Savier & Das (2007) 标准版本
    基准: 12.66 kV, 总负荷约 3802 kW + 2695 kVAr
    辐射状网络,末端欠压明显(最低电压约 0.909 p.u.)
"""
import pandapower as pp

